// --- Komponent LazySection: renderuje treść dopiero gdy element wchodzi w viewport ---
function LazySection({ id, title, paragraphs, index }: { id: string; title: string; paragraphs: string[]; index: number }) {
  const ref = useRef<HTMLDivElement | null>(null);
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    if (!ref.current) return;
    const el = ref.current;
    const obs = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          setVisible(true);
          obs.unobserve(el);
        }
      });
    }, { rootMargin: '0px 0px -10% 0px', threshold: 0.05 });
    obs.observe(el);
    return () => obs.disconnect();
  }, []);

  return (
    <section id={id} ref={ref} style={{ minHeight: '80px' }}>
      <AnimatePresence>
        <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: index * 0.04 }} style={{ background: '#fff', padding: '26px', borderRadius: '18px', boxShadow: '0 6px 24px rgba(0,0,0,0.03)' }}>
          <h2 style={{ fontSize: '1.25rem', fontWeight: 700, marginBottom: '12px' }}>{title}</h2>

          {/* Placeholder skeleton if not visible */}
          {!visible ? (
            <div style={{ display: 'grid', gap: '10px' }}>
              <div style={{ height: '12px', width: '80%', borderRadius: '6px', background: '#f0f0f0' }} />
              <div style={{ height: '12px', width: '95%', borderRadius: '6px', background: '#f0f0f0' }} />
              <div style={{ height: '12px', width: '70%', borderRadius: '6px', background: '#f0f0f0' }} />
            </div>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: '12px', color: '#333', lineHeight: 1.65 }}>
              {paragraphs.map((p, i) => (
                <motion.p key={i} initial={{ opacity: 0, y: 6 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.05 * i }} style={{ margin: 0 }}>
                  {p}
                </motion.p>
              ))}
            </div>
          )}
        </motion.div>
      </AnimatePresence>
    </section>
  );
}

